<div class="flavor-container py-8"><h1 class="text-4xl font-bold mb-4">Plazas de Parking Compartidas</h1><p class="text-lg text-gray-600 mb-8">Encuentra o comparte plazas de parking en tu zona</p><div class="flex flex-col lg:flex-row gap-8"><aside class="lg:w-1/4"><?php include dirname(__FILE__) . '/filters.php'; ?></aside><main class="lg:w-3/4"><?php $q = new WP_Query(array('post_type' => 'parking', 'posts_per_page' => 12)); if ($q->have_posts()) : echo '<div class="grid md:grid-cols-2 xl:grid-cols-3 gap-6">'; while ($q->have_posts()) : $q->the_post(); $ubicacion = get_post_meta(get_the_ID(), '_ubicacion', true); $precio = get_post_meta(get_the_ID(), '_precio_hora', true); $disponible = get_post_meta(get_the_ID(), '_disponible', true); echo '<article class="bg-white rounded-xl shadow-md p-6 hover:shadow-xl transition-all"><h2 class="text-xl font-bold mb-3"><a href="' . get_permalink() . '">' . get_the_title() . '</a></h2>'; if ($ubicacion) echo '<p class="text-gray-600 mb-3 flex items-center gap-2"><svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/></svg>' . esc_html($ubicacion) . '</p>'; if ($precio) echo '<p class="text-2xl font-bold text-primary mb-4">' . esc_html($precio) . '€/hora</p>'; echo '<div class="mb-4">' . ($disponible ? '<span class="bg-green-100 text-green-700 px-3 py-1 rounded-full text-sm font-semibold">Disponible</span>' : '<span class="bg-red-100 text-red-700 px-3 py-1 rounded-full text-sm font-semibold">Ocupado</span>') . '</div>'; echo '<a href="' . get_permalink() . '" class="block text-center px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark">Ver Plaza</a></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">No hay plazas disponibles</h3></div>'; endif; wp_reset_postdata(); ?></main></div></div><?php get_footer(); ?>
